// Extract session token from Authorization: Bearer <token> OR body.session_token.
// This webhook is the SINGLE source of truth used by every other API
// webhook to gate access. It is read-only on the session layer except
// for a sliding-window touch_session() call after a successful match.
const headers = $input.item.json.headers || {};
const body    = $input.item.json.body || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
let token = '';
if (auth.toLowerCase().startsWith('bearer ')) token = auth.slice(7).trim();
if (!token && body.session_token) token = String(body.session_token).trim();
if (!token) return { json: { ok: false, status: 401, error: 'No session token' } };
return { json: { token } };

// validate_session returns 0 or 1 row. 0 = invalid/expired/revoked.
const raw = $input.item.json;
const row = Array.isArray(raw) ? (raw[0] || null) : (raw && (raw.user_id || raw.id) ? raw : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
return { json: {
  ok: true,
  user_id: row.user_id,
  email: row.email,
  user_role: row.user_role,
  client_id: row.client_id,
  expires_at: row.expires_at
} };

// Enforce hard access gates: is_active must be true.
// email_verified is RETURNED but not enforced here — frontend decides whether
// to redirect to /verify-email. (Otherwise the verify page itself would 401.)
// vnd.pgrst.object+json returns a single object OR a PGRST116 error envelope.
const raw = $input.item.json || {};
const session = $('Shape Session').item.json;

// If the view query errored or returned nothing usable, fall back to session-only.
const hasProfile = raw && raw.user_id && raw.is_active !== undefined;

if (hasProfile && raw.is_active === false) {
  return { json: {
    ok: false,
    status: 403,
    error: 'Account suspended. Contact support@crystallux.org.'
  } };
}

// Merge access profile onto session response.
const products = Array.isArray(raw.products) ? raw.products
                : (raw.products && typeof raw.products === 'object' ? raw.products : []);

return { json: {
  ok: true,
  user_id: session.user_id,
  email: session.email,
  user_role: session.user_role,
  client_id: session.client_id,
  expires_at: session.expires_at,
  is_active:        hasProfile ? raw.is_active        : true,
  email_verified:   hasProfile ? raw.email_verified   : false,
  products:         products,
  onboarding_status: hasProfile ? raw.onboarding_status : 'new',
  company_name:     hasProfile ? raw.company_name     : null
} };
